function solve(s: string, k: number): string {
    let result: string[] = [];

    for (let i = 0; i < s.length; i++) {
        const char = s[i];

        if (char === '*') {
            if (result.length > 0) {
                result.pop();
            }
        } else if (char === '#') {
            const copy = [...result];
            result = result.concat(copy);
        } else if (char === '%') {
            result = result.reverse();
        } else {
            result.push(char);
        }
    }

    if (k < 0 || k >= result.length) {
        return '.';
    }

    return result[k];
}
