-spec solve(str :: binary(), k :: integer()) -> string().
solve(Str, K) ->
    Result = process_string(Str),
    case check_k(Result, K) of
        {ok, Char} -> Char;
        _ -> <<".">> end.

process_string(Str) ->
    lists:foldl(
        fun(Char, Acc) ->
            case Char of
                $* -> lists:reverse(lists:split(length(Acc), Acc));
                $# -> lists:append([Acc, Acc]);
                $% -> lists:reverse(Acc);
                _ -> [Char | Acc]
            end
        end,
        [],
        binary_to_list(Str)
    ).

check_k(Result, K) ->
    case K of
        K when K < 0 -> {error, false};
        K when K >= length(Result) -> {error, false};
        _ -> {ok, lists:nth(K + 1, Result)}
    end.
